/**
 * @summary Get all subscription requests (admin)
 */
export const getGetAdminSubscriptionRequestsUrl = (
  params?: GetAdminSubscriptionRequestsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/subscription-requests?${stringifiedParams}`
    : `/api/admin/subscription-requests`;
};

